        private readonly InputActionAsset _asset;
        private readonly InputActionMap _combatMap;
        private readonly InputActionMap _menuMap;

        public InputAction MoveAction { get; }
        public InputAction FightDirectionAction { get; }
        public InputAction GuardAction { get; }
        public InputAction DashAction { get; }
        public InputAction SpecialAction { get; }
        public InputAction NavigateAction { get; }
        public InputAction SubmitAction { get; }
        public InputAction CancelAction { get; }

        public event Action GuardPerformed;
        public event Action DashPerformed;
        public event Action SpecialPerformed;

        public GiantFightInputActions()
        {
            _asset = InputActionAsset.FromJson(ControlsJson);
            _combatMap = _asset.FindActionMap("Combat", throwIfNotFound: true);
            _menuMap = _asset.FindActionMap("Menu", throwIfNotFound: true);

            MoveAction = _combatMap.FindAction("Move", throwIfNotFound: true);
            FightDirectionAction = _combatMap.FindAction("FightDirection", throwIfNotFound: true);
            GuardAction = _combatMap.FindAction("Guard", throwIfNotFound: true);
            DashAction = _combatMap.FindAction("Dash", throwIfNotFound: true);
            SpecialAction = _combatMap.FindAction("Special", throwIfNotFound: true);

            NavigateAction = _menuMap.FindAction("Navigate", throwIfNotFound: true);
            SubmitAction = _menuMap.FindAction("Submit", throwIfNotFound: true);
            CancelAction = _menuMap.FindAction("Cancel", throwIfNotFound: true);

            GuardAction.performed += OnGuardPerformed;
            DashAction.performed += OnDashPerformed;
            SpecialAction.performed += OnSpecialPerformed;
        }

        public void Enable() => _asset.Enable();
        public void Disable() => _asset.Disable();

        public Vector2 Move => MoveAction.ReadValue<Vector2>();
        public Vector2 FightDirection => FightDirectionAction.ReadValue<Vector2>();

        private void OnGuardPerformed(InputAction.CallbackContext _) => GuardPerformed?.Invoke();
        private void OnDashPerformed(InputAction.CallbackContext _) => DashPerformed?.Invoke();
        private void OnSpecialPerformed(InputAction.CallbackContext _) => SpecialPerformed?.Invoke();

        public void Dispose()
        {
            GuardAction.performed -= OnGuardPerformed;
            DashAction.performed -= OnDashPerformed;
            SpecialAction.performed -= OnSpecialPerformed;
            _asset.Dispose();
        }
    }
